const sfx_style = $input.first().json.sfx_style;
const duration_ms = parseInt($input.first().json.sfx_duration_ms);

const sounds = [
  {
    name: 'sword_clash',
    file: 'audio/sfx/sword_clash.mp3',
    prompt: `${sfx_style}, metal sword clashing against metal, sharp ringing impact, bronze blade contact, single strike`,
    duration_ms: 1500,
    tags: 'combat,melee,impact'
