  {
    name: 'arrow_volley',
    file: 'audio/sfx/arrow_volley.mp3',
    prompt: `${sfx_style}, volley of arrows flying through air, multiple arrow whistle sounds, swarm of projectiles, whooshing`,
    duration_ms: 2500,
    tags: 'combat,ranged,projectile'
  },
  {
    name: 'cavalry_charge',
    file: 'audio/sfx/cavalry_charge.mp3',
    prompt: `${sfx_style}, thundering horse hooves galloping, multiple horses charging on dirt, growing louder, cavalry stampede`,
    duration_ms: 3000,
    tags: 'combat,cavalry,movement'
