const ambient_style = $input.first().json.ambient_style;
const duration_s = parseInt($input.first().json.ambient_duration_s);

const ambients = [
  {
    name: 'rain',
    file: 'audio/ambient/rain.mp3',
    prompt: `${ambient_style}, steady rainfall on ancient Chinese battlefield, rain on armor and tents, puddle splashes, moderate intensity rain`,
    duration_s: duration_s,
    tags: 'weather,rain,loop'
  },
  {
    name: 'wind',
    file: 'audio/ambient/wind.mp3',
    prompt: `${ambient_style}, open field wind blowing across grassland, banner flapping in breeze, gentle whistling through mountain pass`,
    duration_s: duration_s,
    tags: 'weather,wind,loop'
  },
  {
    name: 'night_crickets',
    file: 'audio/ambient/night_crickets.mp3',
    prompt: `${ambient_style}, nighttime crickets chirping in Chinese countryside, occasional frog, distant owl, peaceful evening atmosphere`,
    duration_s: duration_s,
    tags: 'night,nature,loop'
  },
  {
    name: 'battlefield_idle',
    file: 'audio/ambient/battlefield_idle.mp3',
    prompt: `${ambient_style}, quiet battlefield before combat, distant murmuring soldiers, occasional metal clink, tense anticipation, wind over open field`,
    duration_s: duration_s,
    tags: 'battlefield,idle,loop'
  }
];

return ambients.map(a => ({
  json: {
    ...a,
    category: 'ambient',
    api: 'stability_audio',
    format: $input.first().json.ambient_format,
    bitrate: $input.first().json.ambient_bitrate,
    output_path: `public/assets/${a.file}`
  }
}));

// Combine all audio categories when 'all' is selected
const music_style = $input.first().json.music_style;
const sfx_style = $input.first().json.sfx_style;
const ambient_style = $input.first().json.ambient_style;

const music = [
  { name: 'battle_theme', file: 'audio/music/battle_theme.mp3', prompt: `${music_style}, intense battle music, fast tempo war drums and erhu, building tension, heroic brass, dramatic crescendo, 120 BPM, loop-friendly ending`, api: 'suno', category: 'music', duration_s: $input.first().json.music_duration_s, format: $input.first().json.music_format, bitrate: $input.first().json.music_bitrate },
  { name: 'deployment_theme', file: 'audio/music/deployment_theme.mp3', prompt: `${music_style}, strategic planning music, calm guzheng melody, contemplative dizi flute, steady pace, thoughtful and measured, 80 BPM, seamless loop`, api: 'suno', category: 'music', duration_s: $input.first().json.music_duration_s, format: $input.first().json.music_format, bitrate: $input.first().json.music_bitrate },
  { name: 'campaign_theme', file: 'audio/music/campaign_theme.mp3', prompt: `${music_style}, epic journey music, sweeping pipa arpeggios, majestic erhu melody, rising strings, sense of adventure and destiny, 100 BPM, grand orchestral`, api: 'suno', category: 'music', duration_s: $input.first().json.music_duration_s, format: $input.first().json.music_format, bitrate: $input.first().json.music_bitrate }
];

const sfx = [
  { name: 'sword_clash', file: 'audio/sfx/sword_clash.mp3', prompt: `${sfx_style}, metal sword clashing against metal, sharp ringing impact, bronze blade contact, single strike`, api: 'elevenlabs', category: 'sfx', duration_ms: 1500, format: $input.first().json.sfx_format, bitrate: $input.first().json.sfx_bitrate },
  { name: 'arrow_volley', file: 'audio/sfx/arrow_volley.mp3', prompt: `${sfx_style}, volley of arrows flying through air, multiple arrow whistle sounds, swarm of projectiles, whooshing`, api: 'elevenlabs', category: 'sfx', duration_ms: 2500, format: $input.first().json.sfx_format, bitrate: $input.first().json.sfx_bitrate },
  { name: 'cavalry_charge', file: 'audio/sfx/cavalry_charge.mp3', prompt: `${sfx_style}, thundering horse hooves galloping, multiple horses charging on dirt, growing louder, cavalry stampede`, api: 'elevenlabs', category: 'sfx', duration_ms: 3000, format: $input.first().json.sfx_format, bitrate: $input.first().json.sfx_bitrate },
  { name: 'horn_signal', file: 'audio/sfx/horn_signal.mp3', prompt: `${sfx_style}, ancient Chinese war horn blast, deep resonant brass horn signal, single sustained note, commanding`, api: 'elevenlabs', category: 'sfx', duration_ms: 2000, format: $input.first().json.sfx_format, bitrate: $input.first().json.sfx_bitrate },
  { name: 'drum_beat', file: 'audio/sfx/drum_beat.mp3', prompt: `${sfx_style}, Chinese war drum beat pattern, deep taiko-style drum hits, rhythmic military cadence, commanding tempo`, api: 'elevenlabs', category: 'sfx', duration_ms: 3000, format: $input.first().json.sfx_format, bitrate: $input.first().json.sfx_bitrate },
  { name: 'unit_rout', file: 'audio/sfx/unit_rout.mp3', prompt: `${sfx_style}, soldiers fleeing in panic, distant shouting and scrambling feet, armor clanking while running, disorganized retreat`, api: 'elevenlabs', category: 'sfx', duration_ms: 2500, format: $input.first().json.sfx_format, bitrate: $input.first().json.sfx_bitrate },
  { name: 'victory_gong', file: 'audio/sfx/victory_gong.mp3', prompt: `${sfx_style}, large Chinese ceremonial gong strike, deep resonant brass gong with long sustain, triumphant single hit`, api: 'elevenlabs', category: 'sfx', duration_ms: 3000, format: $input.first().json.sfx_format, bitrate: $input.first().json.sfx_bitrate },
  { name: 'ui_click', file: 'audio/sfx/ui_click.mp3', prompt: `${sfx_style}, soft wooden click, bamboo tap, subtle UI interaction sound, clean and short`, api: 'elevenlabs', category: 'sfx', duration_ms: 500, format: $input.first().json.sfx_format, bitrate: $input.first().json.sfx_bitrate }
];

const ambient = [
  { name: 'rain', file: 'audio/ambient/rain.mp3', prompt: `${ambient_style}, steady rainfall on ancient Chinese battlefield, rain on armor and tents, puddle splashes, moderate intensity rain`, api: 'stability_audio', category: 'ambient', duration_s: $input.first().json.ambient_duration_s, format: $input.first().json.ambient_format, bitrate: $input.first().json.ambient_bitrate },
  { name: 'wind', file: 'audio/ambient/wind.mp3', prompt: `${ambient_style}, open field wind blowing across grassland, banner flapping in breeze, gentle whistling through mountain pass`, api: 'stability_audio', category: 'ambient', duration_s: $input.first().json.ambient_duration_s, format: $input.first().json.ambient_format, bitrate: $input.first().json.ambient_bitrate },
  { name: 'night_crickets', file: 'audio/ambient/night_crickets.mp3', prompt: `${ambient_style}, nighttime crickets chirping in Chinese countryside, occasional frog, distant owl, peaceful evening atmosphere`, api: 'stability_audio', category: 'ambient', duration_s: $input.first().json.ambient_duration_s, format: $input.first().json.ambient_format, bitrate: $input.first().json.ambient_bitrate },
  { name: 'battlefield_idle', file: 'audio/ambient/battlefield_idle.mp3', prompt: `${ambient_style}, quiet battlefield before combat, distant murmuring soldiers, occasional metal clink, tense anticipation, wind over open field`, api: 'stability_audio', category: 'ambient', duration_s: $input.first().json.ambient_duration_s, format: $input.first().json.ambient_format, bitrate: $input.first().json.ambient_bitrate }
];

const all = [...music, ...sfx, ...ambient].map(a => ({
  json: { ...a, output_path: `public/assets/${a.file}` }
}));

return all;

// FFmpeg post-processing for audio normalization and format conversion
// Requires FFmpeg installed in the n8n environment
//
// For Docker: add `apt-get install -y ffmpeg` to your n8n Dockerfile
// For npm install: ensure ffmpeg is on PATH

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

const items = [];

for (const item of $input.all()) {
  const outputPath = item.json.output_path;
  const format = item.json.format || 'mp3';
  const bitrate = item.json.bitrate || '128k';
  const category = item.json.category;

  // Get binary data
  let inputBuffer;
  if (item.binary && item.binary.data) {
    inputBuffer = Buffer.from(item.binary.data.data, 'base64');
  } else if (item.json.audio_url) {
    // For Suno which returns a URL - download handled separately
    items.push({
      json: {
        ...item.json,
        needs_download: true,
        processing: 'pending'
      }
    });
    continue;
  } else {
    items.push({
      json: {
        error: `No audio data for ${item.json.name}`,
        name: item.json.name
      }
    });
    continue;
  }

  const tmpInput = path.join(os.tmpdir(), `alkaid_${item.json.name}_input.wav`);
  const tmpOutput = path.join(os.tmpdir(), `alkaid_${item.json.name}_output.${format}`);

  try {
    fs.writeFileSync(tmpInput, inputBuffer);

    // Build FFmpeg command based on category
    let ffmpegCmd;
    if (category === 'music' || category === 'ambient') {
      // Normalize loudness, convert format, ensure loop-friendly
      ffmpegCmd = `ffmpeg -y -i "${tmpInput}" -af "loudnorm=I=-16:TP=-1.5:LRA=11,afade=t=out:st=${parseInt(item.json.duration_s || 30) - 2}:d=2" -b:a ${bitrate} "${tmpOutput}"`;
    } else {
      // SFX: normalize, trim silence, convert
      ffmpegCmd = `ffmpeg -y -i "${tmpInput}" -af "silenceremove=start_periods=1:start_silence=0.05:start_threshold=-50dB,loudnorm=I=-14:TP=-1:LRA=7" -b:a ${bitrate} "${tmpOutput}"`;
    }

    execSync(ffmpegCmd, { timeout: 30000 });

    const outputBuffer = fs.readFileSync(tmpOutput);
    const binaryData = await this.helpers.prepareBinaryData(
      outputBuffer,
      `${item.json.name}.${format}`,
      `audio/${format === 'mp3' ? 'mpeg' : format}`
    );

    items.push({
      json: {
        name: item.json.name,
        category: item.json.category,
        output_path: outputPath,
        size: outputBuffer.length,
        format: format,
        processed: true
      },
      binary: {
        data: binaryData
      }
    });

    // Cleanup temp files
    try { fs.unlinkSync(tmpInput); } catch(e) {}
    try { fs.unlinkSync(tmpOutput); } catch(e) {}

  } catch (e) {
    items.push({
      json: {
        error: `FFmpeg processing failed for ${item.json.name}: ${e.message}`,
        name: item.json.name,
        output_path: outputPath
      }
    });
  }
}

return items;

// Summary of audio generation
const results = $input.all();
const summary = {
  total: results.length,
  successful: results.filter(r => !r.json.error).length,
  failed: results.filter(r => r.json.error).length,
  by_category: {
    music: results.filter(r => r.json.category === 'music' && !r.json.error).length,
    sfx: results.filter(r => r.json.category === 'sfx' && !r.json.error).length,
    ambient: results.filter(r => r.json.category === 'ambient' && !r.json.error).length
  },
  errors: results.filter(r => r.json.error).map(r => r.json),
  generated: results.filter(r => !r.json.error).map(r => ({
    name: r.json.name,
    path: r.json.output_path,
    size: r.json.size,
    format: r.json.format
  }))
};

return [{ json: summary }];
